#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int n; scanf("%d",&n);
        int **a = (int**)malloc(n*sizeof(int*));
        for(int i=0;i<n;++i){
            a[i]=(int*)malloc(n*sizeof(int));
            for(int j=0;j<n;++j) scanf("%d",&a[i][j]);
        }
        char **rowKey = (char**)malloc(n*sizeof(char*));
        int *freq = (int*)calloc(n,sizeof(int));
        int distinct=0;
        for(int i=0;i<n;++i){
            char buf[4096]; buf[0]='\0';
            for(int j=0;j<n;++j){
                char tmp[16];
                sprintf(tmp,"%d,",a[i][j]);
                strcat(buf,tmp);
            }
            int found=0;
            for(int k=0;k<distinct;++k){
                if(strcmp(buf,rowKey[k])==0){
                    ++freq[k];
                    found=1;break;
                }
            }
            if(!found){
                rowKey[distinct]=strdup(buf);
                freq[distinct]=1;
                ++distinct;
            }
        }
        long long ans=0;
        for(int j=0;j<n;++j){
            char buf[4096]; buf[0]='\0';
            for(int i=0;i<n;++i){
                char tmp[16];
                sprintf(tmp,"%d,",a[i][j]);
                strcat(buf,tmp);
            }
            for(int k=0;k<distinct;++k){
                if(strcmp(buf,rowKey[k])==0){
                    ans+=freq[k];
                    break;
                }
            }
        }
        printf("%lld\n",ans);
        for(int i=0;i<n;++i) free(a[i]);
        free(a);
        for(int i=0;i<distinct;++i) free(rowKey[i]);
        free(rowKey); free(freq);
    }
    return 0;
}

