import sys

def solve():
    data = sys.stdin.buffer.read().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        n = int(next(it))
        mat = [[int(next(it)) for _ in range(n)] for __ in range(n)]
        row_map = {}
        for row in mat:
            key = tuple(row)
            row_map[key] = row_map.get(key,0) + 1
        ans = 0
        for col in range(n):
            col_tuple = tuple(mat[r][col] for r in range(n))
            ans += row_map.get(col_tuple,0)
        out_lines.append(str(ans))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

